import{_ as e,o,c as t,a as n}from"./app.9c50e1ca.js";const g=JSON.parse('{"title":"Aivius v. Charlieseeese, Dec 2020","description":"","frontmatter":{},"headers":[{"level":2,"title":"Case","slug":"case","link":"#case","children":[]},{"level":2,"title":"Proceedings","slug":"proceedings","link":"#proceedings","children":[]}],"relativePath":"government/court-cases-precedents/aivius_v_charlieseeese_dec_2020.md","lastUpdated":1666539373000}'),i={name:"government/court-cases-precedents/aivius_v_charlieseeese_dec_2020.md"},s=n('<h1 id="aivius-v-charlieseeese-dec-2020" tabindex="-1">Aivius v. Charlieseeese, Dec 2020 <a class="header-anchor" href="#aivius-v-charlieseeese-dec-2020" aria-hidden="true">#</a></h1><h2 id="case" tabindex="-1">Case <a class="header-anchor" href="#case" aria-hidden="true">#</a></h2><p>With Aki presiding, on 21st December 2020, Aivius charged Charlieseeese with Coercive Recruitment and requested that Charlieseeese&#39;s Yoahtlan citizenship be revoked. Charlieseeese was found not guilty.</p><h2 id="proceedings" tabindex="-1">Proceedings <a class="header-anchor" href="#proceedings" aria-hidden="true">#</a></h2><p><strong>Aivius:</strong></p><blockquote><p>I would like to sue Charlieseeese for subverting the citizens and power of Yoahtl by not only coercing new members to join Icenia but to instigate them away from Yoahtl while living primarily in Icenia as an Icenian. I would ask for the removal of citizenship due to these actions which can be seen as treason to some extent. I would like this to be looked under the law of no dual citizenship, as he is primarily seen in Icenia.</p></blockquote><p><strong>SpaceVolcano:</strong></p><blockquote><p>The courts will hear the case of Aivius vs Charlieseeese in the matter of Subverting the Yoahtlan Nation by coercion and instigation of new members to leave Yoahtl and join a foreign Nation.</p></blockquote><blockquote><p>Aki will be presiding</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>Thank you High Justice. To start this trial, I would like to hear an opening statement from the prosecution, Aivius. The channel is open for your opening statement.</p></blockquote><p><strong>Aivius:</strong></p><blockquote><p>Hello fellow Yoahtlans, I bring forth that not only has charlieseeese broken the dual citizenship law but not only primarily living in Icenia, but is apart of its government, has tried stealing members from Yoahtl to Icenia but also encouraging new friends to join Icenia over Yoahtl. As such I think he should be stripped of his citizenship or exiled under these actions. This prohibits the growth and expansion of Yoahtl and subverting the Yoahtlan nation&#39;s power and citizens by doing aforementioned actions.</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>I now ask Charlieseeese to declare guilt or non guilt. In a case of pleading not guilty, then please provide an opening statement</p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>I plead not guilty</p></blockquote><blockquote><p>Ladies and gentlemen of this supposed court,</p></blockquote><blockquote><p>I urge you in the coming deliberation to think about the nature of this case and how it applies to me. I am but a simple newfriend manager and judge of the Icenian court. I will provide bombshell evidence to clear my name that will leave Aivius&#39;s legal reputation in shreds. This will conclude my opening statement.</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>Thank you Charlie</p></blockquote><blockquote><p>The court calls on Aivius to provide evidence for their claim, including witnesses</p></blockquote><p><strong>Aivius:</strong></p><blockquote><p>Sure, I will bring upon example of example a: <a href="https://gyazo.com/9c245a7c8cde225408a8a5e05c33782a" target="_blank" rel="noreferrer">https://gyazo.com/9c245a7c8cde225408a8a5e05c33782a</a></p></blockquote><blockquote><p>In this example I already have been talking to Neo of joining Yoahtl. If charlieseeese is a citizen, then why would he try to steal me to Icenia.</p></blockquote><blockquote><p>Example b: <a href="https://gyazo.com/897ef3a9395cfb15da0ffafe3d974a18" target="_blank" rel="noreferrer">https://gyazo.com/897ef3a9395cfb15da0ffafe3d974a18</a> off that bat he is trying to get someone to move to Icenia over Yoahtl</p></blockquote><blockquote><p>Example c: <a href="https://gyazo.com/dd4f53e95997e27417e420ba9c54f7f5" target="_blank" rel="noreferrer">https://gyazo.com/dd4f53e95997e27417e420ba9c54f7f5</a> Again stating that Icenia is more welcome than Yoahtl. Which again shows he&#39;s not doing his part in helping.</p></blockquote><blockquote><p>Example d: <a href="https://gyazo.com/8b21e846bf0e014c2da7813d1cefb88b" target="_blank" rel="noreferrer">https://gyazo.com/8b21e846bf0e014c2da7813d1cefb88b</a> Here he is again trying to get someone to join Icenia over Yoahtl where he is a citizen of.</p></blockquote><blockquote><p>Example e: <a href="https://gyazo.com/41c42f99e170e951ac31e109ee0ec0b6" target="_blank" rel="noreferrer">https://gyazo.com/41c42f99e170e951ac31e109ee0ec0b6</a> This shows he&#39;s in the Icenian government and is working with them as primary resident</p></blockquote><blockquote><p>Example F: <a href="https://i.imgur.com/jmRMEC3.png" target="_blank" rel="noreferrer">https://i.imgur.com/jmRMEC3.png</a> He is running in the elections for Icenia.</p></blockquote><blockquote><p>With all of this evidence against him. I don&#39;t see how he can defend himself as his actions are completely placed on the table for all to see.</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>Aivius, do you have any witnesses to call on?</p></blockquote><p><strong>Aivius:</strong></p><blockquote><p>I have no witnesses at this time other than the evidence provided.</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>Thank you. The court now calls on Charlieseeese to provide evidence for his defense. This also includes witnesses</p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>I have no witnesses or testimony to provide. I do however have questions for Aivius. If I close my testimony now, may we move on to cross examination?</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>Yes. I will allow cross examination between the prosecution and defense. One question and one response. The order will go defense to prosecution, then prosecution to defense. No scurrilous attacks during the cross, but accusations within the bounds of the trial are allowed</p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>Aivius, do you have any evidence of players who wished to settle in Yoahtl but as a direct result of my actions have chosen to settle in Icenia? I would like to see specific names and evidence that it was my words that caused such a change in plans.</p></blockquote><p><strong>Aivius:</strong></p><blockquote><p>I can&#39;t say I have anyone I can pull as a witness that have joined Icenia over the results of your actions at this present time, but due to the evidence about you have attempted to have 4 people join Icenia along with myself and attempted to do so which shows intent that you&#39;re not helping Yoahtl with new citizens but instead Icenia.</p></blockquote><blockquote><p>I think Example A has the most power there.</p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>So, what you mean to say is that you have no knowledge of specific individuals that have been &quot;stolen&quot; from Yoahtl and have instead moved to Icenia because of me. Is this correct?</p></blockquote><p><strong>Aivius:</strong></p><blockquote><p>I am stating im unaware of how many that could have been stolen from yoahtl, however the evidence shows the intent you have on growing Icenia and not Yoahtl which you are a citizen of.</p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>The plaintiff multiple times during this trial has claimed that I am a citizen of Yoahtl and as such, my actions constitute treason</p></blockquote><blockquote><p>However, I have not been a citizen of Yoahtl for many months. The last recorded time I was a citizen was in August 2020, nearly half a year ago</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/790720154652246076/unknown.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/790720154652246076/unknown.png</a></p></blockquote><blockquote><p>Exhibit A</p></blockquote><blockquote><p>This is a screenshot of the Yoahtlan census of September, 2020</p></blockquote><blockquote><p>It can be clearly seen that my name is not on the list of citizens</p></blockquote><blockquote><p>As such, rumors of dual citizenship do not hold up. My actions were only in accordance to my role as newfriend ambassador of Icenia as assigned to me by Icenian president ChrisChrispie</p></blockquote><blockquote><p>It may appear, given my citizen role on discord, that I am a citizen of Yoahtl. However, the reason I have this role is because of my position as a long time member of the Yoahtl community, as outlined by bg in Exhibit A</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>Aivius, if you have a question for the defendant, present it now</p></blockquote><p><strong>Aivius:</strong></p><blockquote><p>Charlieseeese, You said you were not a citizen for month, but Yoahtl citizenship is for life. The evidence you provided were people who were active enough in Yoahtl to have the role in discord. The was a recent census where you were added back on to that(due to activity). So how can you deny your citizenship when its a lifelong thing?</p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>Can you provide this recent census?</p></blockquote><p><strong>Aivius:</strong></p><blockquote><p>Yes, I will bring my witness NeoTide in on the most recent census done by him.</p></blockquote><blockquote><p>He can present this.</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>Due to the nature of the evidence presented during cross, I will allow neotide to testify</p></blockquote><p><strong>NeoTide:</strong></p><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/790722499406331914/Yoahtlan_Citizenship1.txt" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/790722499406331914/Yoahtlan_Citizenship1.txt</a></p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>I would like to answer the rest of your question, but I must ask, how recent is this census?</p></blockquote><p><strong>NeoTide:</strong></p><blockquote><p>I calculated play times over the last 30 days as of last night</p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>To answer your question, Aivius, I would believe this to be an administrative error.</p></blockquote><blockquote><p>I did not hold citizenship status in the census in september</p></blockquote><blockquote><p>Since then I have not requested citizenship status</p></blockquote><p><strong>Aivius:</strong></p><blockquote><p>How would it be an error if you have citizenship for life?</p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>I do not hold citizenship for life as dual citizenship isn&#39;t typically permitted</p></blockquote><blockquote><p>I am solely a citizen of Icenia</p></blockquote><p><strong>Aivius:</strong></p><blockquote><p>So you&#39;re stating that you&#39;re not a citizen and they your right to citizenship should be revoked?</p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>As far as I am aware, no special status has been given to me</p></blockquote><blockquote><p>What I&#39;m saying is that I haven&#39;t been a citizen for months now and any claims to the contrary do not align with reality. I don&#39;t understand your concept of &quot;right to citizenship,&quot; such a thing does not exist in Yoahtl</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>Despite anyone renouncing citizenship or not, renouncements are not retroactive. I\u2019m still interested in the actions of all involved during the set time scale. I would also advise everyone to review the court proceedings above and see various punishments the courts are able and are not able to issue</p></blockquote><blockquote><p>If either Aivius or Charlieseeese have a question I\u2019ll entertain it now</p></blockquote><p><strong>Aivius:</strong></p><blockquote><p>Charlieseeese, So being a citizen of Yoahtl. Why would you not want the nation to grow by encouraging other to join Icenia, even if they had plans to join/joined yoahtl like myself?</p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>Explain how that is relevant to the charges you have presented</p></blockquote><p><strong>Aivius:</strong></p><blockquote><p>This is on the term of poaching and the intent to poach me for example. I am using myself as a witness.</p></blockquote><blockquote><p>Alongside w/ evidence.</p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>You still have not provided real evidence of me making people that are planning on going to yoahtl go to icenia instead</p></blockquote><p><strong>Aivius:</strong></p><blockquote><p>example A</p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>That\u2019s a loaded question and I refuse to answer it</p></blockquote><p><strong>Aivius:</strong></p><blockquote><p>So you refuse to answer the question because you refuse the proof presented within the question?</p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>I refuse to answer the question because it\u2019s loaded</p></blockquote><p><strong>Aivius:</strong></p><blockquote><p>Is any of it non factual based on the evidence.</p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>I have aleady told you what part of the question I believe is non factual</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>Aivius, is it possible to rephrase the question?</p></blockquote><p><strong>Aivius:</strong></p><blockquote><p>Sure. When I join/joined yoahtl, you have stated to join Icenia. Is it true you that you wanted to recruit me and show intent on stealing me from Yoahtl to Icenia?</p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>Still loaded</p></blockquote><blockquote><p>Maybe try to rephrase the question more</p></blockquote><p><strong>Aivius:</strong></p><blockquote><p>When I join/joined yoahtl, is it true that you tried to recruit me to Icenia?</p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>You hadn\u2019t joined yoahtl yet to my knowledge at the time</p></blockquote><p><strong>Aivius:</strong></p><blockquote><p>I was already building a town and already talked with Neo at that point.</p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>So yes, I did attempt to recruit you because I assumed you were just some other new person</p></blockquote><blockquote><p>How should I know that though</p></blockquote><p><strong>Aivius:</strong></p><blockquote><p>You don&#39;t talk to other citizens about whats happening in Yoahtl?</p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>Not typically</p></blockquote><blockquote><p>I haven\u2019t lived in yoahtl for over a year</p></blockquote><p><strong>Aivius:</strong></p><blockquote><p>Shouldn&#39;t you engage more with your fellow Yoahtlans?</p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>I join VC to listen to IRL drama</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>To avoid loaded questions, please direct questions towards fact finding, not accusations</p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>I don\u2019t typically pay attention to new friends and there plans for towns</p></blockquote><blockquote><p>I\u2019m not sure how me engaging more with my fellow yoahtlans is relevant to this case</p></blockquote><p><strong>Aivius:</strong></p><blockquote><p>Is it true that you&#39;re a member of the Icenian government tasked in recruitment?</p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>Yes</p></blockquote><blockquote><p>I am a judge of the icenian courts</p></blockquote><p><strong>Aivius:</strong></p><blockquote><p>Does that make you a Primary citizen of Icenia?</p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>President ChrisChrispie assigned me to help him with new friends earlier this year as well as my brother</p></blockquote><blockquote><p>It does</p></blockquote><p><strong>Aivius:</strong></p><blockquote><p>I rest my case.</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>Ok, does Charlie have any questions?</p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>No your honor</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>is there any further evidence anyone wants to bring forward? This includes witnesses</p></blockquote><p><strong>Aivius:</strong></p><blockquote><p>No your honor.</p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>Not at this time your honor</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>Thank you both</p></blockquote><blockquote><p>Aivius, any closing statements?</p></blockquote><p><strong>Aivius:</strong></p><blockquote><p>Yes, your honor.</p></blockquote><blockquote><p>I will say that today will be a court case to show how this court is ran. Charlieseeese has already renounced his citizenship alongside his brother which he stated &quot;you can&#39;t renounce what you don&#39;t have&quot; So even though he is legally a citizen. I think along with the evidence and intent provided should show the court and its patrons the fact that Charlieseeese as an Icenian official who wants to take new friends who even think about joining Yoahtl such as I have already shown and stated.</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>Aivius, thank you for the closing statement</p></blockquote><blockquote><p>Charlieseeese, any closing statements</p></blockquote><p><strong>Charlieseeese:</strong></p><blockquote><p>Yes your honor</p></blockquote><blockquote><p>Ladies and gentlemen of this alleged court</p></blockquote><blockquote><p>The conclusion to this trial from the very start has been clear. The plaintiff has built his case upon nothing but jealousy and rumours. He has provided no evidence besides screenshots of me telling newfriends they should come to Icenia. Let it be known that when directly asked, the plaintiff failed to give even one name of a newfriend who, as a result of my intervention, settled in Icenia rather than Yoahtl. I have merely acted in my role as newfriend ambassador for Icenia and have never in my career convinced a newfriend on their way to Yoahtl to come to Icenia instead. Even if his claims were factual, the plaintiff can not paint this as grounds for exile from a community which I have been a part of since the very start of the server (and longer).</p></blockquote><blockquote><p>If the glove fits you must acquit</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>Thank you</p></blockquote><blockquote><p>To begin my decision, I want to express exactly what the court can and cannot do. The court can inflict punishment on citizens and residents of yoahtl for the committing of a crime, and can further remove citizenship from someone as a result of a case. However, to my knowledge, a court case has never explicitly removed citizenship as a permanent punishment for a crime. In every case where citizenship was revoked, there was a condition for restoration of that citizenry. Another point was that the revocation of that citizenry was done for the benefit of the nation as a whole and for the victims of the defendant, such as in cases of harassment. The court cannot exile people for their crimes. The only president on this is in cases where the defendant was on the PoS list, thus would de facto be exiled anyway. Nothing Charlie did was grounds for being on the PoS list, thus he won&#39;t be exiled.</p></blockquote><blockquote><p>On to the decision, as dictated by the charter, every yoahtlan citizen has a right to the freedom of speech and expression. To this end, I think that Charlie\u2019s status as a dual citizen shouldnt impose on his right to expression, and if that means he tells people in ! chat to join icenia then so be it. However, Aivius also has the freedom FROM Harassment. I view Charlie repeatedly asking Aivius, as well as other people mentioned, to join Icenia after refusal as a violation of this freedom from harassment.</p></blockquote><blockquote><p>Just as Charlie&#39;s freedom of expression isn&#39;t limited by his dual citizenship, dual citizenship doesn&#39;t mean you can violate the terms of harassment. Another big part of the case was that Charlie was a member of the Icenian government while he was recruiting people. I don&#39;t want to impose limitations on dual citizens from serving in governments in the future, however, I would be remiss if there wasn\u2019t a concern over conflicts of interests in this case. I would encourage the yoahtlan government to either discuss with the ololtic on this issue or issue laws and decisions regarding this imposition.</p></blockquote><blockquote><p>One question brought up multiple times but was not engaged with was the concept of \u2018Primary residence\u2019 of Charlie. THis case was not directly about this, so my decision was not greatly affected by this line of discussion, but I do want to express that owning property in yoahtl does not make it your primary residence. Tankbuster44, for example, isn&#39;t a citizen because he owns the HJ Industries building. I would advise the council, Olotic, or alcuahtl to find a better precedent for determining primary residence that would allow for bgbba to be a citizen despite his time spent on the gor, but not include people who may spend many hours in yoahtl but be leading other towns.</p></blockquote><blockquote><p>As for the recruitment question. I find it silly to punish anyone for trying to recruit newfriends to their nation. No nation has a monopoly on newfriends and we certainly don&#39;t want to impose nations on newfriends without their knowledge. However, I do find it a bit silly that people are making concerted efforts to recruit yoahtlans into icenia. Not all the evidence presented painted a picture of a concerted effort to destroy or damage yoahtl, however. It did paint a picture of charlies attempting to recruit newfriends and trying to recruit residents of yoahtl to icenia. While the court cannot dictate that dual citizens lose the right to free speech, the court does state that in the future, any attempts to poach or recruit yoahtlan citizens repeatedly is viewed as harassment and will be punished as such.</p></blockquote><blockquote><p>However since I aim not to post-hoc punish charlie, I find him not guilty of this complaint. I encourage future judges, however, take this court case into consideration if Charlie, or any other dual citizen, attempts to harass yoahtlans into joining another nation.</p></blockquote>',188),a=[s];function r(l,c,h,u,p,d){return o(),t("div",null,a)}const k=e(i,[["render",r]]);export{g as __pageData,k as default};
